<?php require_once __DIR__.'/../../includes/bootstrap.php'; require_login(); use app\Services\BookService; $q=$_GET['q']??''; $page=max(1,(int)($_GET['page']??1)); $result=(new BookService())->paginate($q,$page,10); $rows=$result['data']; $pg=paginate_info($result['total'],$page,10); $title='Quản lý sách'; include ROOT_PATH.'/includes/header.php'; ?><div class="d-flex justify-content-between mb-3"><h1 class="h3">Sách</h1><a class="btn btn-primary" href="create.php">Thêm sách</a></div><form class="row mb-3"><div class="col-md-10"><input name="q" class="form-control" placeholder="Tìm theo tên, ISBN, tác giả..." value="<?= e($q) ?>"></div><div class="col-md-2"><button class="btn btn-outline-primary w-100">Tìm</button></div></form><div class="table-responsive"><table class="table table-bordered table-striped"><tr><th>ISBN</th><th>Tên sách</th><th>Loại</th><th>Tác giả</th><th>SL</th><th width="220">Thao tác</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['isbn']) ?></td><td><?= e($r['title']) ?></td><td><?= e($r['type_name']) ?></td><td><?= e($r['author']) ?></td><td><?= e($r['quantity']) ?></td><td><a class="btn btn-sm btn-info" href="detail.php?id=<?= $r['id'] ?>">Xem</a> <a class="btn btn-sm btn-warning" href="edit.php?id=<?= $r['id'] ?>">Sửa</a> <a data-confirm="Xóa sách này?" class="btn btn-sm btn-danger" href="delete.php?id=<?= $r['id'] ?>">Xóa</a></td></tr><?php endforeach; ?></table></div><nav><ul class="pagination"><?php for($i=1;$i<=$pg['total_pages'];$i++): ?><li class="page-item <?= $i==$page?'active':'' ?>"><a class="page-link" href="?q=<?= urlencode($q) ?>&page=<?= $i ?>"><?= $i ?></a></li><?php endfor; ?></ul></nav><?php include ROOT_PATH.'/includes/footer.php'; ?>
